import type { FacetDetails } from "../types/facet";

/**
 * Search and replace substring in Key on URLSearchParams
 * remove when urls have been replace on Matrix
 *
 * @param {object} params URLSearchParams object for the current page.
 * @param {string} target substring to replace
 * @param {replacement} replacement substring to replace
 * @return {object} - URLSearchParams object of new replace keys.
 */

export function replaceAndDeleteKeys(
  params: URLSearchParams | { [key: string]: string },
  target: string,
  replacement: string,
) {
  let entries: [string, string][];
  if (params instanceof URLSearchParams) {
    entries = Array.from(params.entries());
  } else {
    entries = Object.entries(params);
  }

  for (const [key, value] of entries) {
    if (key.includes(target)) {
      const newKey = key.replace(target, replacement);
      if (params instanceof URLSearchParams) {
        params.set(newKey, value); // Add new key
        params.delete(key); // Delete old key
      } else {
        params[newKey] = value;
        delete params[key];
      }
    }
  }

  return params;
}

/**
 * Retrieve non FB parameters from the URL parameters
 *
 * @param {object[]} facets Array of facet definitions.
 * @param {object} params URLSearchParams object for the current page.
 * @return {object} - Map of facet meta labels to their current value from the URL.
 */
export function isURLSearchParams(obj: {[key: string]: string | string[]} | URLSearchParams): obj is URLSearchParams {
  return typeof obj?.get === "function";
}

export function getNonFBParams(
  facets: FacetDetails[],
  params: URLSearchParams | { [key: string]: string | string[]}
) {

  if (isURLSearchParams(params)) {
    return facets
      .filter((facet) => facet.nonFBParam)
      .map((facet) => {
        const param: { [key: string]: string } = {};
        const value = params.get(facet.meta);
        if (value) {
          param[facet.meta] = value;
        }
        return param;
      })
      .reduce((facetParams, facet) => Object.assign(facetParams, facet), {});
  } else {
    return facets
      .map((facet) => {
        const param: { [key: string]: string } = {};
        if ((params as {[key: string]: string})[facet.meta]) {
          param[facet.meta] = (params as {[key: string]: string})[facet.meta];
        }
        return param;
      })
      .reduce((facetParams, facet) => Object.assign(facetParams, facet), {});
  }
}

export function getFacetParams(
  facets: FacetDetails[],
  params: URLSearchParams | { [key: string]: string | string[] }
) {
  const result: { [key: string]: string | string[] } = {};

  if (params instanceof URLSearchParams) {
    for (const facet of facets) {
      const metaKey = `meta_${facet.meta}_sand`;
      const fbKey = `f±${facet.facetName}|${facet.meta}[]`;

      const metaValues = params.getAll(metaKey);
      const fbValues = params.getAll(fbKey);

      if (metaValues.length > 0) {
        // meta_* behaves normally
        result[facet.meta] =
          metaValues.length === 1 ? metaValues[0] : metaValues;
      } else if (fbValues.length > 0) {
        // f±* ALWAYS array
        result[facet.meta] = fbValues;
      }
    }
  } else {
    const typedParams = params as { [key: string]: string | string[] };

    for (const facet of facets) {
      const key = `meta_${facet.meta}_sand`;
      const keyMultiFacet = `f±${facet.facetName}|${facet.meta}[]`;

      if (typedParams[key]) {
        result[facet.meta] = typedParams[key];
      } else if (typedParams[keyMultiFacet]) {
        const value = typedParams[keyMultiFacet];
        result[facet.meta] = Array.isArray(value) ? value : [value];
      } else{
        result[facet.meta] = '';
      }
    }
  }

  return result;
}



